# Instructions ----
#' This file follows the format generated by FIMS:::use_testthat_template().
#' Necessary tests include input and output (IO) correctness [IO
#' correctness], edge-case handling [Edge handling], and built-in errors and
#' warnings [Error handling]. See `?FIMS:::use_testthat_template` for more
#' information. Every test should have a @description tag, which can only span
#' one lines, that will be used in the bookdown report of the results from
#' {testthat}. This line can be more than 80 characters.

# setup_default_BevertonHoltRecruitment ----
## Setup ----
data <- FIMS::FIMSFrame(data_big)

## IO correctness ----
test_that("`setup_default_BevertonHoltRecruitment()` works with correct inputs", {
  result <- FIMS:::setup_default_BevertonHoltRecruitment(data = data, distribution = "Dnorm")

  #' @description Test that key recruitment labels are present.
  expect_true(tibble::is_tibble(result))
  result_labels <- unique(result[["label"]])
  expect_equal(result_labels, c("log_rzero", "logit_steep", "log_devs"))
  expect_true(all(result[["module_name"]] == "Recruitment"))

  clear()
})

## Edge handling ----
test_that("`setup_default_BevertonHoltRecruitment()` works with edge cases", {
  result <- FIMS:::setup_default_BevertonHoltRecruitment(data = data, distribution = NA_character_)

  #' @description Test that `log_devs` become constant when no process distribution is provided.
  expect_equal(
    result |>
      dplyr::filter(.data[["label"]] == "log_devs") |>
      dplyr::pull(.data[["estimation_type"]]) |>
      unique(),
    "constant"
  )

  clear()
})

## Error handling ----
test_that("`setup_default_BevertonHoltRecruitment()` returns correct error messages", {
  #' @description Test that invalid `data` class returns expected error.
  expect_error(
    object = FIMS:::setup_default_BevertonHoltRecruitment(data = "not_a_fimsframe"),
    regexp = "FIMSFrame"
  )

  clear()
})
